queries.sparql:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasContent_Promotions ?child ; p:hasStreamings ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streamings } }
  FILTER(?nf = ?total)
}

